import 'package:btech_tokens/btech_tokens.dart';
import '../dropdown-list/dropdown_list.types.dart';
import '../dropdown-list/dropdown_list.widget.dart';
import 'package:flutter/material.dart';

// ── Internal constants ─────────────────────────────────────────────────────

const double _kGap = 4;
const double _kEllipsisBtnSize = 24;
const double _kEllipsisBtnRadius = 6;

// ── Public widgets ─────────────────────────────────────────────────────────

/// BTBreadcrumb — compositional breadcrumb root.
///
/// Figma: node 681:10168
///
/// Compose with [BTBreadcrumbItem], [BTBreadcrumbLink], [BTBreadcrumbPage],
/// [BTBreadcrumbSeparator], and [BTBreadcrumbEllipsis].
///
/// ```dart
/// BTBreadcrumb(
///   children: [
///     BTBreadcrumbItem(child: BTBreadcrumbLink(label: 'Home', onTap: _noop)),
///     const BTBreadcrumbSeparator(),
///     BTBreadcrumbItem(
///       child: BTBreadcrumbEllipsis(
///         dropdownItems: [
///           BTBreadcrumbLink(label: 'Category', onTap: _noop),
///         ],
///       ),
///     ),
///     const BTBreadcrumbSeparator(),
///     const BTBreadcrumbItem(child: BTBreadcrumbPage(label: 'Detail')),
///   ],
/// )
/// ```
class BTBreadcrumb extends StatelessWidget {
  const BTBreadcrumb({required this.children, super.key});

  final List<Widget> children;

  @override
  Widget build(BuildContext context) {
    return Semantics(
      label: 'Breadcrumb navigation',
      child: Wrap(
        alignment: WrapAlignment.center,
        crossAxisAlignment: WrapCrossAlignment.center,
        spacing: _kGap,
        runSpacing: _kGap,
        children: children,
      ),
    );
  }
}

/// Wrapper for a single step in the breadcrumb trail.
class BTBreadcrumbItem extends StatelessWidget {
  const BTBreadcrumbItem({required this.child, super.key});

  final Widget child;

  @override
  Widget build(BuildContext context) => child;
}

/// Clickable breadcrumb link.
///
/// When [onTap] is null the text still renders but without a tap gesture.
class BTBreadcrumbLink extends StatelessWidget {
  const BTBreadcrumbLink({required this.label, this.onTap, super.key});

  final String label;
  final VoidCallback? onTap;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    return GestureDetector(
      onTap: onTap,
      child: Text(
        label,
        style: TextStyle(
          fontSize: 14.0,
          fontWeight: FontWeight.w500,
          height: 16 / 14,
          color: colors.text.secondary,
          decoration: TextDecoration.none,
        ),
      ),
    );
  }
}

/// Non-interactive current-page label (aria-current equivalent).
class BTBreadcrumbPage extends StatelessWidget {
  const BTBreadcrumbPage({required this.label, super.key});

  final String label;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    return Text(
      label,
      style: TextStyle(
        fontSize: 14.0,
        fontWeight: FontWeight.w500,
        height: 16 / 14,
        color: colors.text.primary,
        decoration: TextDecoration.none,
      ),
    );
  }
}

/// Chevron separator between breadcrumb steps.
class BTBreadcrumbSeparator extends StatelessWidget {
  const BTBreadcrumbSeparator({super.key});

  @override
  Widget build(BuildContext context) {
    return Icon(
      Icons.chevron_right,
      size: 16,
      color: context.btColor.text.secondary,
    );
  }
}

/// Ellipsis (···) button that opens a [BTDropdownList] overlay.
///
/// Pass collapsed steps as [dropdownItems]. Each item's [BTBreadcrumbLink.onTap]
/// is called when the user selects that row.
class BTBreadcrumbEllipsis extends StatefulWidget {
  const BTBreadcrumbEllipsis({required this.dropdownItems, super.key});

  final List<BTBreadcrumbLink> dropdownItems;

  @override
  State<BTBreadcrumbEllipsis> createState() => _BTBreadcrumbEllipsisState();
}

class _BTBreadcrumbEllipsisState extends State<BTBreadcrumbEllipsis> {
  final _btnKey = GlobalKey();
  OverlayEntry? _overlay;
  bool _open = false;

  @override
  void dispose() {
    _removeOverlay();
    super.dispose();
  }

  void _removeOverlay() {
    _overlay?.remove();
    _overlay = null;
  }

  void _toggle() {
    if (_open) {
      _removeOverlay();
      setState(() => _open = false);
    } else {
      _showOverlay();
    }
  }

  void _showOverlay() {
    final renderBox =
        _btnKey.currentContext?.findRenderObject() as RenderBox?;
    if (renderBox == null) return;

    final pos = renderBox.localToGlobal(Offset.zero);
    final size = renderBox.size;
    final textDir = Directionality.of(context);

    // Convert BTBreadcrumbLink list → BTDropdownItem<int> list
    final listItems = widget.dropdownItems
        .asMap()
        .entries
        .map(
          (e) => BTDropdownItem<int>(
            value: e.key,
            label: e.value.label,
          ),
        )
        .toList();

    _overlay = OverlayEntry(
      builder: (ctx) => Directionality(
        textDirection: textDir,
        child: Material(
          color: Colors.transparent,
          child: Stack(
            children: [
              Positioned.fill(
                child: GestureDetector(
                  behavior: HitTestBehavior.translucent,
                  onTap: () {
                    _removeOverlay();
                    if (mounted) setState(() => _open = false);
                  },
                ),
              ),
              Positioned(
                top: pos.dy + size.height + 4,
                left: pos.dx - 40,
                child: BTDropdownList<int>(
                  variant: BTDropdownListVariant.list,
                  items: listItems,
                  onSelect: (idx) {
                    _removeOverlay();
                    if (mounted) setState(() => _open = false);
                    widget.dropdownItems[idx].onTap?.call();
                  },
                ),
              ),
            ],
          ),
        ),
      ),
    );

    Overlay.of(context).insert(_overlay!);
    setState(() => _open = true);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    return GestureDetector(
      key: _btnKey,
      onTap: _toggle,
      child: Container(
        width: _kEllipsisBtnSize,
        height: _kEllipsisBtnSize,
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(_kEllipsisBtnRadius),
          color: _open ? colors.bg.secondary : Colors.transparent,
        ),
        alignment: Alignment.center,
        child: Icon(
          Icons.more_horiz,
          size: 16,
          color: colors.text.secondary,
        ),
      ),
    );
  }
}

// Internal constants for BTBreadcrumb — Figma node 681:10168.

const String kBreadcrumbChevronAsset =
    'packages/btech_ui/assets/icons/breadcrumb/chevron_right.svg';

const String kBreadcrumbMoreAsset =
    'packages/btech_ui/assets/icons/breadcrumb/more_horiz.svg';

/// Height of each item in the ellipsis popup.
const double kBreadcrumbDropdownItemHeight = 24;

/// Horizontal padding inside each dropdown item.
const double kBreadcrumbDropdownItemPaddingH = 12;

/// Vertical padding inside the dropdown container.
const double kBreadcrumbDropdownPaddingV = 4;

/// Gap between breadcrumb items (separator + text).
const double kBreadcrumbGap = 4;

/// Icon size for chevron separator.
const double kBreadcrumbChevronWidth = 8;
const double kBreadcrumbChevronHeight = 14;

/// Icon size for more_horiz ellipsis button.
const double kBreadcrumbMoreSize = 16;
